    // "signals": [
    //   {
    //     "name": "buffer_zone_type",
    //     "value": "buffer_zone_1",
    //     "bind": {
    //       "input": "select",
    //       "options": ["buffer_zone_1", "buffer_zone_2", "buffer_zone_3", "hazard_zone_1"],
    //       "name": "Zone Id: "
    //     }
    //   }
    // ]
    "data": [
      {
        "name": "parsed_data",
        "url": {
          "index": "mdx-frames-*",
          "body": {
            "size": 500,
            "sort": [{ "timestamp": { "order": "desc" } }],
            "query": {
              "range": {
                "timestamp": {
                  "gte": {"%timefilter%": "min"},
                  "lte": {"%timefilter%": "max"}
                }
              }
            },
            "_source": ["timestamp", "rois"]
          }
        },
        "format": { "property": "hits.hits" },
        "transform": [
          {
            "type": "flatten",
            "fields": ["_source.rois"],
            "as": ["roi"]
          },
          {
            "type": "formula",
            "expr": "datum.roi.type || 'N/A'",
            "as": "roi_type"
          },
          {
              "type": "filter",
              "expr": "datum.roi.id == 'hazard_zone_1'"
            },
          {
            "type": "formula",
            "expr": "datum.roi.info ? datum.roi.info.restrictedAreaViolation : 'false'",
            "as": "restrictedAreaViolation"
          },
          {
            "type": "formula",
            "expr": "datum.roi.objectIds",
            "as": "roi_objectIds"
          },
          {
            "type": "formula",
            "expr": "datum.roi_objectIds ? datum.roi_objectIds.length : 0",
            "as": "violation_count"
          },
          {
            "type": "project",
            "fields": ["_source.timestamp", "roi_type", "violation_count", "restrictedAreaViolation"],
            "as": ["minute_time", "object_type", "avg_count", "restrictedAreaViolation"]
          },
          {
            "type": "filter",
            "expr": "datum.restrictedAreaViolation == 'true'"
          },
          {
            "type": "window",
            "ops": ["row_number"],
            "as": ["row_id"]
          },
          {
            "type": "filter",
            "expr": "datum.row_id <= 24"
          },
          {
            "type": "collect",
            "sort": {"field": "minute_time", "order": "ascending"}
          }
        ]
      }
    ],
    "scales": [
      {
        "name": "x",
        "type": "point",
        "domain": {"data": "parsed_data", "field": "minute_time"},
        "range": [0, {"signal": "width"}],
        "padding": 0.2
      },
      {
        "name": "y",
        "type": "linear",
        "domain": {"data": "parsed_data", "field": "avg_count"},
        "range": [{"signal": "height"}, 0],
        "nice": true,
        "zero": true,
        "padding": 0.2
      },
      {
        "name": "color",
        "type": "ordinal",
        "domain": {"data": "parsed_data", "field": "object_type"},
        "range": {"scheme": "category10"}
      },
      {
        "name": "xOffset",
        "type": "band",
        "domain": {"data": "parsed_data", "field": "object_type"},
        "range": [0, 20]
      }
    ],
    "axes": [
      {
        "orient": "bottom",
        "scale": "x",
        "title": "Time",
        "labelAngle": -15,
        "labelAlign": "right",
        "labelBaseline": "middle"
      },
      {
        "orient": "left",
        "scale": "y",
        "title": "Violation Count"
      }
    ],
    "legends": [
      {
        "fill": "color",
        "title": "Object Type",
        "encode": {
          "symbols": {
            "enter": {
              "fillOpacity": {"value": 1}
            }
          }
        }
      }
    ],
    "marks": [
      {
        "type": "rect",
        "from": {"data": "parsed_data"},
        "encode": {
          "enter": {
            "x": {
              "scale": "x",
              "field": "minute_time",
              "offset": {"scale": "xOffset", "field": "object_type"}
            },
            "width": {"scale": "xOffset", "band": 1},
            "y": {"scale": "y", "field": "avg_count"},
            "y2": {"scale": "y", "value": 0},
            "fill": {"scale": "color", "field": "object_type"},
            "tooltip": {
              "signal": "{'time': datum.minute_time, 'roi': datum.roi_id, 'type': datum.object_type, 'count': format(datum.avg_count, '.1f')}"
            }
