    "width": 1500,
    "height": 500,
    "padding": {
      "top": 20,
      "bottom": 80,
      "left": 80,
      "right": 182
    },
    "data": [
      {
        "name": "es",
        "url": {
          "index": "mdx-frames-*",
          "body": {
            "size": 0,
            "query": {
              "bool": {
                "filter": [
                  {"range": {"timestamp": {"gte": {"%timefilter%": "min"}, "lte": {"%timefilter%": "max"}}}}
                ]
              }
            },
            "aggs": {
              "by_time": {
                "auto_date_histogram": {
                  "field": "timestamp",
                  "buckets": 16
                },
                "aggs": {
                  "by_fov": {
                    "nested": {
                      "path": "fov"
                    },
                    "aggs": {
                      "by_type": {
                        "terms": {
                          "field": "fov.type.keyword",
                          "size": 10
                        },
                        "aggs": {
                          "avg_count": {
                            "avg": {
                              "field": "fov.count"
                            }
                          }
                        }
                      }
                    }
                  }
                }
              }
            }
          }
        },
        "format": {"property": "aggregations.by_time.buckets"}
      },
      {
        "name": "parsed_data",
        "source": "es",
        "transform": [
          {
            "type": "flatten",
            "fields": ["by_fov.by_type.buckets"],
            "as": ["type_bucket"]
          },
          {
            "type": "formula",
            "expr": "datum.type_bucket.key",
            "as": "object_type"
          },
          {
            "type": "formula",
            "expr": "datum.type_bucket.avg_count.value",
            "as": "avg_count"
          },
          {
            "type": "formula",
            "expr": "datum.key_as_string",
            "as": "minute_time"
          }
        ]
      }
    ],
    "scales": [
      {
        "name": "x",
        "type": "point",
        "domain": {"data": "parsed_data", "field": "minute_time"},
